# Exempel med fel ordning på if-satserna,
# betyg(95) borde ge ett A.

def betyg(poäng):
  """Konvertera poäng till betyg"""
  if poäng >= 50:
    return "E"
  elif poäng >= 60: 
    return "D"
  elif poäng >= 70:
    return "C"
  elif poäng >= 80:
    return "B"
  elif poäng >= 90:
    return "A"
  else:
    return "F"

print(betyg(45))
print(betyg(55))
print(betyg(65))
print(betyg(75))
print(betyg(85))
print(betyg(95))
